int F(int A[], int n) {
    int j = 0;
    for (int i = 0; i < n; i++) {
        if (A[i] % 2 == 0) {
            if (A[j] % 2 != 0) {
                int t = A[i];
                A[i] = A[j];
                A[j] = t;
            }
            j = j + 1;
        }
    }
